    val isConfirmEnabled by remember {
        derivedStateOf {
            state.projectName.isNotBlank() && state.kilometres.isDigitsOnly()
        }
    }

    Scaffold(
        topBar = { SingleProjectTopBar(onNavigateBack = onNavigateBack) }
    ) { padding ->
        SingleProjectContent(
            padding = padding,
            screenState = SingleProjectScreenState(
                date = date,
                state = state,
                isAddMode = args.index == -1,
                uiState = projectsUiState,
                isConfirmEnabled = isConfirmEnabled
            ),
            actions = SingleProjectActions(
                onStateChange = { state = it },
                onOpenWorkday = { onOpenWorkday(state) },
                onConfirm = {
                    viewModel.saveProject(uiState = state.toUiState())
                    onNavigateBack()
                }
            )
        )
    }
}

private fun Context.findActivity(): ComponentActivity {
    var context = this
    while (context is ContextWrapper) {
        if (context is ComponentActivity) return context
        context = context.baseContext
    }
    error("Context does not have an Activity")
}

@OptIn(ExperimentalMaterial3Api::class)
@Composable
private fun SingleProjectTopBar(onNavigateBack: () -> Unit) {
    CenterAlignedTopAppBar(
        title = {
            Header(
                title = stringResource(id = R.string.project_customer),
                modifier = Modifier.padding(top = 0.dp)
            )
        },
        navigationIcon = {
            IconButton(onClick = onNavigateBack) {
                Icon(imageVector = Icons.AutoMirrored.Filled.ArrowBack, contentDescription = null)
            }
        },
        actions = {
            Spacer(modifier = Modifier.width(width = 48.dp))
        }
    )
}

data class SingleProjectScreenState(
    val date: String,
    val state: ProjectDialogState,
    val isAddMode: Boolean,
    val uiState: ProjectsUiState,
    val isConfirmEnabled: Boolean
)

data class SingleProjectActions(
    val onStateChange: (ProjectDialogState) -> Unit,
    val onOpenWorkday: () -> Unit,
    val onConfirm: () -> Unit
)

@Composable
private fun SingleProjectContent(
    padding: PaddingValues,
    screenState: SingleProjectScreenState,
    actions: SingleProjectActions
) {
    Column(
        modifier = Modifier
            .fillMaxSize()
            .padding(paddingValues = padding)
            .padding(all = 24.dp)
            .verticalScroll(state = rememberScrollState()),
        verticalArrangement = Arrangement.spacedBy(space = 20.dp),
        horizontalAlignment = Alignment.CenterHorizontally,
    ) {
        HeaderSection(date = screenState.date)

        DialogMainFields(
            state = screenState.state,
            isAddMode = screenState.isAddMode,
            onStateChange = actions.onStateChange
        )

        TimeSelectionSection(
            state = screenState.state,
            workTimeToday = screenState.uiState.workTimeToday,
            onOpenWorkday = actions.onOpenWorkday,
            onStateChange = actions.onStateChange
        )

        DialogDropdownFields(
            state = screenState.state,
            workTypeDropDownList = screenState.uiState.workTypes,
            onStateChange = actions.onStateChange
        )

        Spacer(modifier = Modifier.weight(weight = 1f))

        Button(
            onClick = actions.onConfirm,
            enabled = screenState.isConfirmEnabled,
            modifier = Modifier.fillMaxWidth(),
            shape = RoundedCornerShape(size = 12.dp)
        ) {
            Text(text = stringResource(id = R.string.save), style = MaterialTheme.typography.titleMedium)
        }
    }
}

@Composable
private fun HeaderSection(date: String) {
    ElevatedCard(
        modifier = Modifier.fillMaxWidth()
    ) {
        Column(
            modifier = Modifier.padding(all = 16.dp),
            horizontalAlignment = Alignment.CenterHorizontally,
            verticalArrangement = Arrangement.spacedBy(space = 8.dp)
        ) {
            Text(
                text = date,
                style = MaterialTheme.typography.headlineMedium,
                fontWeight = FontWeight.Bold,
                color = MaterialTheme.colorScheme.primary,
                textAlign = TextAlign.Center,
                modifier = Modifier.fillMaxWidth()
            )
        }
    }
}

@Composable
private fun DialogMainFields(
    state: ProjectDialogState,
    isAddMode: Boolean,
    onStateChange: (ProjectDialogState) -> Unit
) {
    Column(verticalArrangement = Arrangement.spacedBy(space = 16.dp)) {
        OutlinedTextField(
            value = state.projectName,
            onValueChange = { onStateChange(state.copy(projectName = it)) },
            label = { Text(text = stringResource(id = R.string.project_name)) },
            modifier = Modifier.fillMaxWidth(),
            enabled = isAddMode,
            singleLine = true,
            shape = RoundedCornerShape(size = 12.dp)
        )

        OutlinedTextField(
            value = state.kilometres,
            onValueChange = { if (it.isDigitsOnly()) onStateChange(state.copy(kilometres = it)) },
            label = { Text(text = stringResource(id = R.string.kilometres)) },
            modifier = Modifier.fillMaxWidth(),
            keyboardOptions = KeyboardOptions(keyboardType = KeyboardType.Number),
            singleLine = true,
            shape = RoundedCornerShape(size = 12.dp)
        )
    }
}

@Composable
private fun TimeSelectionSection(
    state: ProjectDialogState,
    workTimeToday: String,
    onOpenWorkday: () -> Unit,
    onStateChange: (ProjectDialogState) -> Unit
) {
    Column(verticalArrangement = Arrangement.spacedBy(space = 12.dp)) {
        CompactTimeRow(
            labelId = R.string.work_time,
            value = state.projectTime,
            onOpenWorkday = onOpenWorkday,
            onHistoryClick = {
                onStateChange(state.copy(projectTime = workTimeToday))
            }
        )
    }
}

@Composable
private fun DialogDropdownFields(
    state: ProjectDialogState,
    workTypeDropDownList: List<String>,
    onStateChange: (ProjectDialogState) -> Unit
) {
    Column(verticalArrangement = Arrangement.spacedBy(space = 12.dp)) {
        DropdownMenuBox(
            items = listOf(
                stringResource(id = R.string.no_allowance),
                stringResource(id = R.string.daily_allowance),
                stringResource(id = R.string.half_day_allowance)
            ),
            onItemSelected = { onStateChange(state.copy(allowance = it)) },
            labelId = R.string.allowance,
            selectedText = state.allowance,
            modifier = Modifier.fillMaxWidth()
        )

        DropdownMenuBox(
            items = workTypeDropDownList,
            onItemSelected = { onStateChange(state.copy(workType = it)) },
            labelId = R.string.work_type,
            selectedText = state.workType,
            modifier = Modifier.fillMaxWidth()
        )
    }
}

@Composable
private fun CompactTimeRow(
    labelId: Int,
    value: String,
    onOpenWorkday: () -> Unit,
    onHistoryClick: () -> Unit
) {
    Row(
        verticalAlignment = Alignment.CenterVertically,
        horizontalArrangement = Arrangement.spacedBy(space = 8.dp),
        modifier = Modifier.fillMaxWidth()
    ) {
        OutlinedTextField(
            value = value,
            onValueChange = {},
            label = { Text(text = stringResource(id = labelId)) },
            readOnly = true,
            modifier = Modifier.weight(weight = 1f),
            colors = OutlinedTextFieldDefaults.colors(
                disabledTextColor = MaterialTheme.colorScheme.onSurface,
                disabledLabelColor = MaterialTheme.colorScheme.onSurfaceVariant,
                disabledBorderColor = MaterialTheme.colorScheme.outline,
            ),
            shape = RoundedCornerShape(size = 12.dp)
        )

        IconButton(onClick = onHistoryClick) {
            Icon(
                imageVector = Icons.Default.History,
                contentDescription = null,
                tint = MaterialTheme.colorScheme.primary
            )
        }

        IconButton(onClick = onOpenWorkday) {
            Icon(
                imageVector = Icons.Default.AccessTime,
                contentDescription = null,
                tint = MaterialTheme.colorScheme.primary
            )
        }
    }
}

package com.akiwiksten.worktime30.core

import java.time.LocalDate
import java.time.LocalTime
import java.time.format.DateTimeFormatter
import kotlin.math.abs

/**
 * Pure logic for time calculations and workday balance.
 * This class is stateless and provides calculation results back to the caller.
 */
@Suppress("TooManyFunctions")
object WorkTimeCalculator {

    private val timeFormatter = DateTimeFormatter.ofPattern(TIME_FORMAT)
    private val dayFormatter = DateTimeFormatter.ofPattern("dd")

    fun parseDate(workday: String): String {
        // Optimization: LocalDate.parse is relatively slow.
        // If workday is always in ISO format (yyyy-MM-dd), we can just take the last 2 chars.
        return if (workday.length >= 10 && workday[4] == '-' && workday[7] == '-') {
            workday.substring(8, 10)
        } else {
            val formattedDate = LocalDate.parse(workday)
            dayFormatter.format(formattedDate)
        }
    }

    fun stringToLocalTime(time: String): LocalTime {
        return LocalTime.parse(time, timeFormatter)
    }

    fun calculateWorkTimeBalance(initialTime: String, addedTime: String): String {
        val isInitialNegative = initialTime.startsWith("-")
        val isAddedNegative = addedTime.startsWith("-")

        val cleanInitial = if (isInitialNegative) initialTime.substring(1) else initialTime
        val cleanAdded = if (isAddedNegative) addedTime.substring(1) else addedTime

        return calculateTotalMinutes(
            initialTime = cleanInitial,
            addedTime = cleanAdded,
            isInitialTimeNegative = isInitialNegative,
            isAddedTimeNegative = isAddedNegative
        )
    }

    fun calculateTotalMinutes(
        initialTime: String,
        addedTime: String,
        isInitialTimeNegative: Boolean,
        isAddedTimeNegative: Boolean
    ): String {
        val initialTotalMinutes = timeToMinutes(initialTime)
        val addedTotalMinutes = timeToMinutes(addedTime)

        val initialSign = if (isInitialTimeNegative) -1 else 1
        val addedSign = if (isAddedTimeNegative) -1 else 1

        val totalMinutes = (initialTotalMinutes * initialSign) + (addedTotalMinutes * addedSign)

        val absTotal = abs(totalMinutes)
        val hours = absTotal / MINUTES_IN_HOUR
        val minutes = absTotal % MINUTES_IN_HOUR

        val sign = if (totalMinutes < 0) "-" else ""

        // Optimization: Use StringBuilder or manual padding instead of String.format for performance
        return buildString(6) {
            append(sign)
            if (hours < 10) append('0')
            append(hours)
            append(':')
            if (minutes < 10) append('0')
            append(minutes)
        }
    }

    fun calculateStartTimeUpdate(params: StartTimeUpdateParams): TimeUpdateResult {
        return if (params.isNewDay) {
            val end = params.start.add(params.dailyWorkTime).add(params.lunchTime)
            val lunchStart = calculateHalfTime(params.start, params.dailyWorkTime)
            TimeUpdateResult(
                endTime = end.toString(),
                lunchStart = lunchStart.toString(),
                lunchEnd = lunchStart.add(params.lunchTime).toString(),
                breakStart = params.start.toString(),
                breakEnd = params.start.toString()
            )
        } else if (params.workTimeToday != LocalTime.MIDNIGHT) {
            val newWorkTimeToday = params.workTimeToday.subtract(params.start).add(params.oldStartTime)
            TimeUpdateResult(workTimeToday = newWorkTimeToday.toString())
        } else {
            TimeUpdateResult()
        }
    }

    fun calculateEndTimeUpdate(params: EndTimeUpdateParams): TimeUpdateResult {
        val newWorkTimeToday = if (params.workTimeToday == LocalTime.MIDNIGHT) {
            params.end.subtract(params.start).subtract(params.lunchEnd).add(params.lunchStart)
                .subtract(params.breakEnd).add(params.breakStart)
        } else {
            params.workTimeToday.subtract(params.oldEndTime).add(params.end)
        }
        return TimeUpdateResult(workTimeToday = newWorkTimeToday.toString())
    }

    fun calculateDailyWorkTimeUpdate(
        end: LocalTime,
        dailyWorkTime: LocalTime,
        workTimeToday: LocalTime,
        oldDailyWorkTime: LocalTime,
        isNewDay: Boolean
    ): TimeUpdateResult {
        return if (!isNewDay && workTimeToday == LocalTime.MIDNIGHT) {
            val newEnd = end.subtract(oldDailyWorkTime).add(dailyWorkTime)
            TimeUpdateResult(endTime = newEnd.toString())
        } else {
            TimeUpdateResult()
        }
    }

    fun calculateLunchStartUpdate(
        lunchStart: LocalTime,
        lunchTime: LocalTime,
        workTimeToday: LocalTime,
        oldLunchStart: LocalTime,
        currentLunchEnd: LocalTime
    ): TimeUpdateResult {
        val newLunchEnd = if (workTimeToday == LocalTime.MIDNIGHT) {
            lunchStart.add(lunchTime)
        } else {
            currentLunchEnd.subtract(oldLunchStart).add(lunchStart)
        }
        return TimeUpdateResult(lunchEnd = newLunchEnd.toString())
    }

    fun calculateLunchEndUpdate(
        end: LocalTime,
        lunchEnd: LocalTime,
        workTimeToday: LocalTime,
        oldLunchEnd: LocalTime
    ): TimeUpdateResult {
        return if (workTimeToday == LocalTime.MIDNIGHT) {
            val newEnd = end.subtract(oldLunchEnd).add(lunchEnd)
            TimeUpdateResult(endTime = newEnd.toString())
        } else {
            val newWorkTimeToday = workTimeToday.subtract(lunchEnd).add(oldLunchEnd)
            TimeUpdateResult(workTimeToday = newWorkTimeToday.toString(), calculateBalance = true)
        }
    }

    fun calculateLunchTimeUpdate(
        end: LocalTime,
        lunchStart: LocalTime,
        lunchTime: LocalTime,
        workTimeToday: LocalTime,
        oldLunchTime: LocalTime
    ): TimeUpdateResult {
        return if (workTimeToday == LocalTime.MIDNIGHT) {
            val newEnd = end.add(lunchTime).subtract(oldLunchTime)
            val newLunchEnd = lunchStart.add(lunchTime)
            TimeUpdateResult(endTime = newEnd.toString(), lunchEnd = newLunchEnd.toString())
        } else {
            TimeUpdateResult()
        }
    }

    fun calculateBreakStartUpdate(
        end: LocalTime,
        breakStart: LocalTime,
        breakEnd: LocalTime,
        workTimeToday: LocalTime,
        oldBreakStart: LocalTime
    ): TimeUpdateResult {
        return when {
            oldBreakStart == breakEnd -> TimeUpdateResult(breakEnd = breakStart.toString())
            workTimeToday == LocalTime.MIDNIGHT -> {
                val newEnd = end.subtract(oldBreakStart).add(breakEnd)
                TimeUpdateResult(endTime = newEnd.toString())
            }
            else -> {
                val newWorkTimeToday = workTimeToday.subtract(oldBreakStart).add(breakStart)
                TimeUpdateResult(workTimeToday = newWorkTimeToday.toString(), calculateBalance = true)
            }
        }
    }

    fun calculateBreakEndUpdate(
        end: LocalTime,
        workTimeToday: LocalTime,
        breakEnd: LocalTime,
        oldBreakEnd: LocalTime
    ): TimeUpdateResult {
        return if (workTimeToday == LocalTime.MIDNIGHT) {
            val newEnd = end.subtract(oldBreakEnd).add(breakEnd)
            TimeUpdateResult(endTime = newEnd.toString())
        } else {
            val newWorkTimeToday = workTimeToday.subtract(breakEnd).add(oldBreakEnd)
            TimeUpdateResult(workTimeToday = newWorkTimeToday.toString(), calculateBalance = true)
        }
    }

    fun calculateWorkTimeTodayUpdate(
        end: LocalTime,
        dailyWorkTime: LocalTime,
        workTimeToday: LocalTime,
        oldWorkTimeToday: LocalTime
    ): TimeUpdateResult {
        val newEnd = if (oldWorkTimeToday == LocalTime.MIDNIGHT) {
            end.subtract(dailyWorkTime).add(workTimeToday)
        } else {
            end.subtract(oldWorkTimeToday).add(workTimeToday)
        }
        return TimeUpdateResult(endTime = newEnd.toString())
    }

    private fun LocalTime.subtract(time: LocalTime): LocalTime {
        return minusHours(time.hour.toLong()).minusMinutes(time.minute.toLong())
    }

    private fun LocalTime.add(time: LocalTime): LocalTime {
        return plusHours(time.hour.toLong()).plusMinutes(time.minute.toLong())
    }

    private fun timeToMinutes(time: String): Int {
        val colonIndex = time.indexOf(':')
        if (colonIndex == -1) return 0
        val hours = time.substring(0, colonIndex).toInt()
        val minutes = time.substring(colonIndex + 1).toInt()
        return hours * MINUTES_IN_HOUR + minutes
    }

    private fun calculateHalfTime(start: LocalTime, dailyWorkTime: LocalTime): LocalTime {
        val totalMinutes = (dailyWorkTime.hour * MINUTES_IN_HOUR + dailyWorkTime.minute) / 2
        return start.plusMinutes(totalMinutes.toLong())
    }

    fun checkIfDoubleMinus(value: String): String {
        return if (value.startsWith("--")) value.substring(2) else value
    }

    data class TimeUpdateResult(
        val endTime: String? = null,
        val lunchStart: String? = null,
        val lunchEnd: String? = null,
        val breakStart: String? = null,
        val breakEnd: String? = null,
        val workTimeToday: String? = null,
        val calculateBalance: Boolean = false
    )

    data class StartTimeUpdateParams(
        val start: LocalTime,
        val dailyWorkTime: LocalTime,
        val lunchTime: LocalTime,
        val workTimeToday: LocalTime,
        val oldStartTime: LocalTime,
        val isNewDay: Boolean
    )

    data class EndTimeUpdateParams(
        val start: LocalTime,
        val end: LocalTime,
        val lunchStart: LocalTime,
        val lunchEnd: LocalTime,
        val breakStart: LocalTime,
        val breakEnd: LocalTime,
        val workTimeToday: LocalTime,
        val oldEndTime: LocalTime
    )
}

package com.akiwiksten.worktime30.core

import java.time.LocalDate
import java.time.LocalTime
import java.time.format.DateTimeFormatter
import kotlin.math.abs

/**
 * Pure logic for time calculations and workday balance.
 * This class is stateless and provides calculation results back to the caller.
 */
@Suppress("TooManyFunctions")
object WorkTimeCalculator {

    private val timeFormatter = DateTimeFormatter.ofPattern(TIME_FORMAT)
    private val dayFormatter = DateTimeFormatter.ofPattern("dd")

    /**
     * Returns day-of-month (`dd`) extracted from [workday].
     *
     * Expected [workday] format: `yyyy-MM-dd` (for example `2026-04-13`).
     * For this exact ISO format, the function uses substring extraction for performance.
     */
    fun parseDate(workday: String): String {
        // Optimization: LocalDate.parse is relatively slow.
        // If workday is always in ISO format (yyyy-MM-dd), we can just take the last 2 chars.
        return if (workday.length >= 10 && workday[4] == '-' && workday[7] == '-') {
            workday.substring(8, 10)
        } else {
            val formattedDate = LocalDate.parse(workday)
            dayFormatter.format(formattedDate)
        }
    }

    fun stringToLocalTime(time: String): LocalTime {
        return LocalTime.parse(time, timeFormatter)
    }

    fun calculateWorkTimeBalance(initialTime: String, addedTime: String): String {
        val isInitialNegative = initialTime.startsWith("-")
        val isAddedNegative = addedTime.startsWith("-")

        val cleanInitial = if (isInitialNegative) initialTime.substring(1) else initialTime
        val cleanAdded = if (isAddedNegative) addedTime.substring(1) else addedTime

        return calculateTotalMinutes(
            initialTime = cleanInitial,
            addedTime = cleanAdded,
            isInitialTimeNegative = isInitialNegative,
            isAddedTimeNegative = isAddedNegative
        )
    }

    fun calculateTotalMinutes(
        initialTime: String,
        addedTime: String,
        isInitialTimeNegative: Boolean,
        isAddedTimeNegative: Boolean
    ): String {
        val initialTotalMinutes = timeToMinutes(initialTime)
        val addedTotalMinutes = timeToMinutes(addedTime)

        val initialSign = if (isInitialTimeNegative) -1 else 1
        val addedSign = if (isAddedTimeNegative) -1 else 1

        val totalMinutes = (initialTotalMinutes * initialSign) + (addedTotalMinutes * addedSign)

        val absTotal = abs(totalMinutes)
        val hours = absTotal / MINUTES_IN_HOUR
        val minutes = absTotal % MINUTES_IN_HOUR

        val sign = if (totalMinutes < 0) "-" else ""

        // Optimization: Use StringBuilder or manual padding instead of String.format for performance
        return buildString(6) {
            append(sign)
            if (hours < 10) append('0')
            append(hours)
            append(':')
            if (minutes < 10) append('0')
            append(minutes)
        }
    }

    fun calculateStartTimeUpdate(params: StartTimeUpdateParams): TimeUpdateResult {
        return if (params.isNewDay) {
            val end = params.start.add(params.dailyWorkTime).add(params.lunchTime)
            val lunchStart = calculateHalfTime(params.start, params.dailyWorkTime)
            TimeUpdateResult(
                endTime = end.toString(),
                lunchStart = lunchStart.toString(),
                lunchEnd = lunchStart.add(params.lunchTime).toString(),
                breakStart = params.start.toString(),
                breakEnd = params.start.toString()
            )
        } else if (params.workTimeToday != LocalTime.MIDNIGHT) {
            val newWorkTimeToday = params.workTimeToday.subtract(params.start).add(params.oldStartTime)
            TimeUpdateResult(workTimeToday = newWorkTimeToday.toString())
        } else {
            TimeUpdateResult()
        }
    }

    fun calculateEndTimeUpdate(params: EndTimeUpdateParams): TimeUpdateResult {
        val newWorkTimeToday = if (params.workTimeToday == LocalTime.MIDNIGHT) {
            params.end.subtract(params.start).subtract(params.lunchEnd).add(params.lunchStart)
                .subtract(params.breakEnd).add(params.breakStart)
        } else {
            params.workTimeToday.subtract(params.oldEndTime).add(params.end)
        }
        return TimeUpdateResult(workTimeToday = newWorkTimeToday.toString())
    }

    fun calculateDailyWorkTimeUpdate(
        end: LocalTime,
        dailyWorkTime: LocalTime,
        workTimeToday: LocalTime,
        oldDailyWorkTime: LocalTime,
        isNewDay: Boolean
    ): TimeUpdateResult {
        return if (!isNewDay && workTimeToday == LocalTime.MIDNIGHT) {
            val newEnd = end.subtract(oldDailyWorkTime).add(dailyWorkTime)
            TimeUpdateResult(endTime = newEnd.toString())
        } else {
            TimeUpdateResult()
        }
    }

    fun calculateLunchStartUpdate(
        lunchStart: LocalTime,
        lunchTime: LocalTime,
        workTimeToday: LocalTime,
        oldLunchStart: LocalTime,
        currentLunchEnd: LocalTime
    ): TimeUpdateResult {
        val newLunchEnd = if (workTimeToday == LocalTime.MIDNIGHT) {
            lunchStart.add(lunchTime)
        } else {
            currentLunchEnd.subtract(oldLunchStart).add(lunchStart)
        }
        return TimeUpdateResult(lunchEnd = newLunchEnd.toString())
    }

    fun calculateLunchEndUpdate(
        end: LocalTime,
        lunchEnd: LocalTime,
        workTimeToday: LocalTime,
        oldLunchEnd: LocalTime
    ): TimeUpdateResult {
        return if (workTimeToday == LocalTime.MIDNIGHT) {
            val newEnd = end.subtract(oldLunchEnd).add(lunchEnd)
            TimeUpdateResult(endTime = newEnd.toString())
        } else {
            val newWorkTimeToday = workTimeToday.subtract(lunchEnd).add(oldLunchEnd)
            TimeUpdateResult(workTimeToday = newWorkTimeToday.toString(), calculateBalance = true)
        }
    }

    fun calculateLunchTimeUpdate(
        end: LocalTime,
        lunchStart: LocalTime,
        lunchTime: LocalTime,
        workTimeToday: LocalTime,
        oldLunchTime: LocalTime
    ): TimeUpdateResult {
        return if (workTimeToday == LocalTime.MIDNIGHT) {
            val newEnd = end.add(lunchTime).subtract(oldLunchTime)
            val newLunchEnd = lunchStart.add(lunchTime)
            TimeUpdateResult(endTime = newEnd.toString(), lunchEnd = newLunchEnd.toString())
        } else {
            TimeUpdateResult()
        }
    }

    fun calculateBreakStartUpdate(
        end: LocalTime,
        breakStart: LocalTime,
        breakEnd: LocalTime,
        workTimeToday: LocalTime,
        oldBreakStart: LocalTime
    ): TimeUpdateResult {
        return when {
            oldBreakStart == breakEnd -> TimeUpdateResult(breakEnd = breakStart.toString())
            workTimeToday == LocalTime.MIDNIGHT -> {
                val newEnd = end.subtract(oldBreakStart).add(breakEnd)
                TimeUpdateResult(endTime = newEnd.toString())
            }
            else -> {
                val newWorkTimeToday = workTimeToday.subtract(oldBreakStart).add(breakStart)
                TimeUpdateResult(workTimeToday = newWorkTimeToday.toString(), calculateBalance = true)
            }
        }
    }

    fun calculateBreakEndUpdate(
        end: LocalTime,
        workTimeToday: LocalTime,
        breakEnd: LocalTime,
        oldBreakEnd: LocalTime
    ): TimeUpdateResult {
        return if (workTimeToday == LocalTime.MIDNIGHT) {
            val newEnd = end.subtract(oldBreakEnd).add(breakEnd)
            TimeUpdateResult(endTime = newEnd.toString())
        } else {
            val newWorkTimeToday = workTimeToday.subtract(breakEnd).add(oldBreakEnd)
            TimeUpdateResult(workTimeToday = newWorkTimeToday.toString(), calculateBalance = true)
        }
    }

    fun calculateWorkTimeTodayUpdate(
        end: LocalTime,
        dailyWorkTime: LocalTime,
        workTimeToday: LocalTime,
        oldWorkTimeToday: LocalTime
    ): TimeUpdateResult {
        val newEnd = if (oldWorkTimeToday == LocalTime.MIDNIGHT) {
            end.subtract(dailyWorkTime).add(workTimeToday)
        } else {
            end.subtract(oldWorkTimeToday).add(workTimeToday)
        }
        return TimeUpdateResult(endTime = newEnd.toString())
    }

    private fun LocalTime.subtract(time: LocalTime): LocalTime {
        return minusHours(time.hour.toLong()).minusMinutes(time.minute.toLong())
    }

    private fun LocalTime.add(time: LocalTime): LocalTime {
        return plusHours(time.hour.toLong()).plusMinutes(time.minute.toLong())
    }

    private fun timeToMinutes(time: String): Int {
        val colonIndex = time.indexOf(':')
        if (colonIndex == -1) return 0
        val hours = time.substring(0, colonIndex).toInt()
        val minutes = time.substring(colonIndex + 1).toInt()
        return hours * MINUTES_IN_HOUR + minutes
    }

    private fun calculateHalfTime(start: LocalTime, dailyWorkTime: LocalTime): LocalTime {
        val totalMinutes = (dailyWorkTime.hour * MINUTES_IN_HOUR + dailyWorkTime.minute) / 2
        return start.plusMinutes(totalMinutes.toLong())
    }

    fun checkIfDoubleMinus(value: String): String {
        return if (value.startsWith("--")) value.substring(2) else value
    }

    data class TimeUpdateResult(
        val endTime: String? = null,
        val lunchStart: String? = null,
        val lunchEnd: String? = null,
        val breakStart: String? = null,
        val breakEnd: String? = null,
        val workTimeToday: String? = null,
        val calculateBalance: Boolean = false
    )

    data class StartTimeUpdateParams(
        val start: LocalTime,
        val dailyWorkTime: LocalTime,
        val lunchTime: LocalTime,
        val workTimeToday: LocalTime,
        val oldStartTime: LocalTime,
        val isNewDay: Boolean
    )

    data class EndTimeUpdateParams(
        val start: LocalTime,
        val end: LocalTime,
        val lunchStart: LocalTime,
        val lunchEnd: LocalTime,
        val breakStart: LocalTime,
        val breakEnd: LocalTime,
        val workTimeToday: LocalTime,
        val oldEndTime: LocalTime
    )
}

package com.akiwiksten.worktime30.core.calculator

import com.akiwiksten.worktime30.core.MINUTES_IN_HOUR
import java.time.LocalTime

/**
 * Calculates dependent time-field updates for Project Details form edits.
 */
object ProjectDetailsTimeUpdateCalculator {
    fun calculateStartTimeUpdate(
        params: WorkTimeCalculator.StartTimeUpdateParams
    ): WorkTimeCalculator.TimeUpdateResult {
        return if (params.isNewDay) {
            val end = params.start.add(params.dailyWorkTime).add(params.lunchTime)
            val lunchStart = calculateHalfTime(params.start, params.dailyWorkTime)
            WorkTimeCalculator.TimeUpdateResult(
                end = end.toString(),
                lunchStart = lunchStart.toString(),
                lunchEnd = lunchStart.add(params.lunchTime).toString(),
                breakStart = params.start.toString(),
                breakEnd = params.start.toString()
            )
        } else if (params.projectTime != LocalTime.MIDNIGHT) {
            val newProjectTime = params.projectTime.subtract(params.start).add(params.oldStartTime)
            WorkTimeCalculator.TimeUpdateResult(projectTime = newProjectTime.toString())
        } else {
            WorkTimeCalculator.TimeUpdateResult()
        }
    }

    fun calculateEndTimeUpdate(params: WorkTimeCalculator.EndTimeUpdateParams): WorkTimeCalculator.TimeUpdateResult {
        val newProjectTime = if (params.projectTime == LocalTime.MIDNIGHT) {
            params.end.subtract(params.start).subtract(params.lunchEnd).add(params.lunchStart)
                .subtract(params.breakEnd).add(params.breakStart)
        } else {
            params.projectTime.subtract(params.oldEndTime).add(params.end)
        }
        return WorkTimeCalculator.TimeUpdateResult(projectTime = newProjectTime.toString())
    }

    fun calculateDailyWorkTimeUpdate(
        end: LocalTime,
        dailyWorkTime: LocalTime,
        projectTime: LocalTime,
        oldDailyWorkTime: LocalTime,
        isNewDay: Boolean
    ): WorkTimeCalculator.TimeUpdateResult {
        return if (!isNewDay && projectTime == LocalTime.MIDNIGHT) {
            val newEnd = end.subtract(oldDailyWorkTime).add(dailyWorkTime)
            WorkTimeCalculator.TimeUpdateResult(end = newEnd.toString())
        } else {
            WorkTimeCalculator.TimeUpdateResult()
        }
    }

    fun calculateLunchStartUpdate(
        lunchStart: LocalTime,
        lunchTime: LocalTime,
        projectTime: LocalTime,
        oldLunchStart: LocalTime,
        currentLunchEnd: LocalTime
    ): WorkTimeCalculator.TimeUpdateResult {
        val newLunchEnd = if (projectTime == LocalTime.MIDNIGHT) {
            lunchStart.add(lunchTime)
        } else {
            currentLunchEnd.subtract(oldLunchStart).add(lunchStart)
        }
        return WorkTimeCalculator.TimeUpdateResult(lunchEnd = newLunchEnd.toString())
    }

    fun calculateLunchEndUpdate(
        end: LocalTime,
        lunchEnd: LocalTime,
        projectTime: LocalTime,
        oldLunchEnd: LocalTime
    ): WorkTimeCalculator.TimeUpdateResult {
        return if (projectTime == LocalTime.MIDNIGHT) {
            val newEnd = end.subtract(oldLunchEnd).add(lunchEnd)
            WorkTimeCalculator.TimeUpdateResult(end = newEnd.toString())
        } else {
            val newProjectTime = projectTime.subtract(lunchEnd).add(oldLunchEnd)
            WorkTimeCalculator.TimeUpdateResult(
                projectTime = newProjectTime.toString(),
                shouldRecalculateFlexTime = true
            )
        }
    }

    fun calculateLunchTimeUpdate(
        end: LocalTime,
        lunchStart: LocalTime,
        lunchTime: LocalTime,
        projectTime: LocalTime,
        oldLunchTime: LocalTime
    ): WorkTimeCalculator.TimeUpdateResult {
        return if (projectTime == LocalTime.MIDNIGHT) {
            val newEnd = end.add(lunchTime).subtract(oldLunchTime)
            val newLunchEnd = lunchStart.add(lunchTime)
            WorkTimeCalculator.TimeUpdateResult(end = newEnd.toString(), lunchEnd = newLunchEnd.toString())
        } else {
            WorkTimeCalculator.TimeUpdateResult()
        }
    }

    fun calculateBreakStartUpdate(
        end: LocalTime,
        breakStart: LocalTime,
        breakEnd: LocalTime,
        projectTime: LocalTime,
        oldBreakStart: LocalTime
    ): WorkTimeCalculator.TimeUpdateResult {
        return when {
            oldBreakStart == breakEnd -> WorkTimeCalculator.TimeUpdateResult(breakEnd = breakStart.toString())
            projectTime == LocalTime.MIDNIGHT -> {
                val newEnd = end.subtract(oldBreakStart).add(breakEnd)
                WorkTimeCalculator.TimeUpdateResult(end = newEnd.toString())
            }
            else -> {
                val newProjectTime = projectTime.subtract(oldBreakStart).add(breakStart)
                WorkTimeCalculator.TimeUpdateResult(
                    projectTime = newProjectTime.toString(),
                    shouldRecalculateFlexTime = true
                )
            }
        }
    }

    fun calculateBreakEndUpdate(
        end: LocalTime,
        projectTime: LocalTime,
        breakEnd: LocalTime,
        oldBreakEnd: LocalTime
    ): WorkTimeCalculator.TimeUpdateResult {
        return if (projectTime == LocalTime.MIDNIGHT) {
            val newEnd = end.subtract(oldBreakEnd).add(breakEnd)
            WorkTimeCalculator.TimeUpdateResult(end = newEnd.toString())
        } else {
            val newProjectTime = projectTime.subtract(breakEnd).add(oldBreakEnd)
            WorkTimeCalculator.TimeUpdateResult(
                projectTime = newProjectTime.toString(),
                shouldRecalculateFlexTime = true
            )
        }
    }

    fun calculateProjectTimeUpdate(
        end: LocalTime,
        dailyWorkTime: LocalTime,
        projectTime: LocalTime,
        oldProjectTime: LocalTime
    ): WorkTimeCalculator.TimeUpdateResult {
        val newEnd = if (oldProjectTime == LocalTime.MIDNIGHT) {
            end.subtract(dailyWorkTime).add(projectTime)
        } else {
            end.subtract(oldProjectTime).add(projectTime)
        }
        return WorkTimeCalculator.TimeUpdateResult(end = newEnd.toString())
    }
}

private fun calculateHalfTime(start: LocalTime, dailyWorkTime: LocalTime): LocalTime {
    val totalMinutes = (dailyWorkTime.hour * MINUTES_IN_HOUR + dailyWorkTime.minute) / 2
    return start.plusMinutes(totalMinutes.toLong())
}

private fun LocalTime.subtract(time: LocalTime): LocalTime {
    return minusHours(time.hour.toLong()).minusMinutes(time.minute.toLong())
}

private fun LocalTime.add(time: LocalTime): LocalTime {
    return plusHours(time.hour.toLong()).plusMinutes(time.minute.toLong())
}

