fun WorkStatsState.toWorkdayEntity(date: String, workTimeToday: String): WorkdayEntity {
    return WorkdayEntity(
        date = date,
        workTimeToday = workTimeToday.ifEmpty { ZERO_TIME },
        workTimeTodayEstimate = dailyWorkTime
    )
}

