package com.akiwiksten.worktime30.feature.settings

import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import com.akiwiksten.worktime30.core.ZERO_TIME
import com.akiwiksten.worktime30.data.repository.DateRepository
import com.akiwiksten.worktime30.data.repository.ProjectDetailsRepository
import com.akiwiksten.worktime30.data.repository.SettingsRepository
import com.akiwiksten.worktime30.domain.GetSettingsUseCase
import com.akiwiksten.worktime30.domain.GetWorkdayByMonthUseCase
import com.akiwiksten.worktime30.domain.SaveSettingsUseCase
import com.akiwiksten.worktime30.feature.workday.SingleProjectState
import dagger.hilt.android.lifecycle.HiltViewModel
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.launch
import java.time.LocalDate
import javax.inject.Inject

sealed class SettingsUiState {
    object Loading : SettingsUiState()

    data class Success(
        val data: SettingsState
    ) : SettingsUiState()

    data class Error(val message: String) : SettingsUiState()
}

data class SettingsState(
    val name: String = "",
    val employer: String = "",
    val dailyWorkTimeEstimate: String = "",
    val lunchTimeEstimate: String = ZERO_TIME,
    val selectedDate: String = "",
    val endMonthDate: String = "",
    val workTypes: List<String> = emptyList(),
    val projectsByMonth: List<SingleProjectState> = emptyList()
)

@HiltViewModel
class SettingsViewModel @Inject constructor(
    private val getSettingsUseCase: GetSettingsUseCase,
    private val saveSettingsUseCase: SaveSettingsUseCase,
    private val getWorkdayByMonthUseCase: GetWorkdayByMonthUseCase,
    private val settingsRepository: SettingsRepository,
    private val projectDetailsRepository: ProjectDetailsRepository,
    private val dateRepository: DateRepository
) : ViewModel() {

    private val _uiState = MutableStateFlow<SettingsUiState>(SettingsUiState.Loading)
    val uiState: StateFlow<SettingsUiState> = _uiState.asStateFlow()

    init {
        observeDate()
    }

    private fun observeDate() {
        viewModelScope.launch {
            dateRepository.selectedDate.collect { date ->
                if (date.isNotEmpty()) {
                    val currentState = _uiState.value
                    if (currentState is SettingsUiState.Success) {
                        _uiState.value = currentState.copy(
                            data = currentState.data.copy(selectedDate = date)
                        )
                    }
                    loadProjectsByMonth(date)
                }
            }
        }
    }

    fun setName(name: String) {
        val currentState = _uiState.value
        if (currentState is SettingsUiState.Success) {
            _uiState.value = currentState.copy(
                data = currentState.data.copy(name = name)
            )
        }
    }

    fun setEmployer(employer: String) {
        val currentState = _uiState.value
        if (currentState is SettingsUiState.Success) {
            _uiState.value = currentState.copy(
                data = currentState.data.copy(employer = employer)
            )
        }
    }

    fun setDailyWorkTimeEstimate(dailyWorkTimeEstimate: String) {
        val currentState = _uiState.value
        if (currentState is SettingsUiState.Success) {
            _uiState.value = currentState.copy(
                data = currentState.data.copy(dailyWorkTimeEstimate = dailyWorkTimeEstimate)
            )
        }
    }

    fun setLunchTimeEstimate(lunchTimeEstimate: String) {
        val currentState = _uiState.value
        if (currentState is SettingsUiState.Success) {
            _uiState.value = currentState.copy(
                data = currentState.data.copy(lunchTimeEstimate = lunchTimeEstimate)
            )
        }
    }

    fun addWorkType(workType: String) {
        val currentState = _uiState.value
        if (currentState is SettingsUiState.Success) {
            val currentWorkTypes = currentState.data.workTypes
            val updatedWorkTypes = if (workType in currentWorkTypes) {
                currentWorkTypes
            } else {
                (currentWorkTypes + workType).sorted()
            }
            _uiState.value = currentState.copy(
                data = currentState.data.copy(workTypes = updatedWorkTypes)
            )
        }
    }

    fun removeWorkType(workType: String) {
        val currentState = _uiState.value
        if (currentState is SettingsUiState.Success) {
            _uiState.value = currentState.copy(
                data = currentState.data.copy(
                    workTypes = currentState.data.workTypes.filter { it != workType }
                )
            )
        }
        viewModelScope.launch {
            settingsRepository.deleteWorkType(workType)
        }
    }

    fun loadProjectsByMonth(date: String) {
        viewModelScope.launch {
            try {
                val parsedDate = LocalDate.parse(date)
                val endOfMonth = parsedDate
                    .withDayOfMonth(parsedDate.month.length(parsedDate.isLeapYear))
                    .toString()
                val projects = getWorkdayByMonthUseCase(date)
                val currentState = _uiState.value
                if (currentState is SettingsUiState.Success) {
                    _uiState.value = currentState.copy(
                        data = currentState.data.copy(
                            endMonthDate = endOfMonth,
                            projectsByMonth = projects
                        )
                    )
                }
            } catch (e: IllegalArgumentException) {
                handleException(e, "Failed to load projects")
            } catch (e: IllegalStateException) {
                handleException(e, "Failed to load projects")
            }
        }
    }

    fun loadSettings() {
        viewModelScope.launch {
            _uiState.value = SettingsUiState.Loading
            try {
                val loadedData = getSettingsUseCase()
                val currentDate = dateRepository.selectedDate.value
                val workStats = projectDetailsRepository.getWorkStatsByDate(currentDate)
                val parsedDate = LocalDate.parse(currentDate)
                val endOfMonth = parsedDate
                    .withDayOfMonth(parsedDate.month.length(parsedDate.isLeapYear))
                    .toString()
                val projects = getWorkdayByMonthUseCase(currentDate)

                _uiState.value = SettingsUiState.Success(
                    data = SettingsState(
                        name = loadedData.name,
                        employer = loadedData.employer,
                        dailyWorkTimeEstimate = workStats?.dailyWorkTime ?: "",
                        lunchTimeEstimate = workStats?.lunchTime ?: ZERO_TIME,
                        selectedDate = currentDate,
                        endMonthDate = endOfMonth,
                        workTypes = loadedData.workTypes,
                        projectsByMonth = projects
                    )
                )
            } catch (e: IllegalArgumentException) {
                handleException(e, "Failed to load settings")
            } catch (e: IllegalStateException) {
                handleException(e, "Failed to load settings")
            }
        }
    }

    fun saveSettings() {
        viewModelScope.launch {
            try {
                val currentState = _uiState.value
                if (currentState is SettingsUiState.Success) {
                    saveSettingsUseCase(
                        name = currentState.data.name,
                        employer = currentState.data.employer,
                        workTypes = currentState.data.workTypes,
                        dailyWorkTimeEstimate = currentState.data.dailyWorkTimeEstimate,
                        lunchTimeEstimate = currentState.data.lunchTimeEstimate
                    )
                }
            } catch (e: IllegalArgumentException) {
                handleException(e, "Failed to save settings")
            } catch (e: IllegalStateException) {
                handleException(e, "Failed to save settings")
            }
        }
    }

    private fun handleException(exception: Exception, message: String) {
        _uiState.value = SettingsUiState.Error("$message: ${exception.message}")
    }
}

package com.akiwiksten.worktime30.feature.settings

import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import com.akiwiksten.worktime30.core.ZERO_TIME
import com.akiwiksten.worktime30.data.repository.DateRepository
import com.akiwiksten.worktime30.data.repository.ProjectDetailsRepository
import com.akiwiksten.worktime30.data.repository.SettingsRepository
import com.akiwiksten.worktime30.domain.GetSettingsUseCase
import com.akiwiksten.worktime30.domain.GetWorkdayByMonthUseCase
import com.akiwiksten.worktime30.domain.SaveSettingsUseCase
import com.akiwiksten.worktime30.feature.workday.SingleProjectState
import dagger.hilt.android.lifecycle.HiltViewModel
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.launch
import java.time.LocalDate
import javax.inject.Inject

sealed class SettingsUiState {
    object Loading : SettingsUiState()

    data class Success(
        val data: SettingsState
    ) : SettingsUiState()

    data class Error(val message: String) : SettingsUiState()
}

data class SettingsState(
    val name: String = "",
    val employer: String = "",
    val dailyWorkTimeEstimate: String = "",
    val lunchTimeEstimate: String = ZERO_TIME,
    val selectedDate: String = "",
    val endMonthDate: String = "",
    val workTypes: List<String> = emptyList(),
    val projectsByMonth: List<SingleProjectState> = emptyList()
)

@HiltViewModel
class SettingsViewModel @Inject constructor(
    private val getSettingsUseCase: GetSettingsUseCase,
    private val saveSettingsUseCase: SaveSettingsUseCase,
    private val getWorkdayByMonthUseCase: GetWorkdayByMonthUseCase,
    private val settingsRepository: SettingsRepository,
    private val projectDetailsRepository: ProjectDetailsRepository,
    private val dateRepository: DateRepository
) : ViewModel() {

    private val _uiState = MutableStateFlow<SettingsUiState>(SettingsUiState.Loading)
    val uiState: StateFlow<SettingsUiState> = _uiState.asStateFlow()

    init {
        observeDate()
    }

    private fun observeDate() {
        viewModelScope.launch {
            dateRepository.selectedDate.collect { date ->
                if (date.isNotEmpty()) {
                    val currentState = _uiState.value
                    if (currentState is SettingsUiState.Success) {
                        _uiState.value = currentState.copy(
                            data = currentState.data.copy(selectedDate = date)
                        )
                    }
                    loadProjectsByMonth(date)
                }
            }
        }
    }

    fun setName(name: String) {
        val currentState = _uiState.value
        if (currentState is SettingsUiState.Success) {
            _uiState.value = currentState.copy(
                data = currentState.data.copy(name = name)
            )
        }
    }

    fun setEmployer(employer: String) {
        val currentState = _uiState.value
        if (currentState is SettingsUiState.Success) {
            _uiState.value = currentState.copy(
                data = currentState.data.copy(employer = employer)
            )
        }
    }

    fun setDailyWorkTimeEstimate(dailyWorkTimeEstimate: String) {
        val currentState = _uiState.value
        if (currentState is SettingsUiState.Success) {
            _uiState.value = currentState.copy(
                data = currentState.data.copy(dailyWorkTimeEstimate = dailyWorkTimeEstimate)
            )
        }
    }

    fun setLunchTimeEstimate(lunchTimeEstimate: String) {
        val currentState = _uiState.value
        if (currentState is SettingsUiState.Success) {
            _uiState.value = currentState.copy(
                data = currentState.data.copy(lunchTimeEstimate = lunchTimeEstimate)
            )
        }
    }

    fun addWorkType(workType: String) {
        val currentState = _uiState.value
        if (currentState is SettingsUiState.Success) {
            val currentWorkTypes = currentState.data.workTypes
            val updatedWorkTypes = if (workType in currentWorkTypes) {
                currentWorkTypes
            } else {
                (currentWorkTypes + workType).sorted()
            }
            _uiState.value = currentState.copy(
                data = currentState.data.copy(workTypes = updatedWorkTypes)
            )
        }
    }

    fun removeWorkType(workType: String) {
        val currentState = _uiState.value
        if (currentState is SettingsUiState.Success) {
            _uiState.value = currentState.copy(
                data = currentState.data.copy(
                    workTypes = currentState.data.workTypes.filter { it != workType }
                )
            )
        }
        viewModelScope.launch {
            settingsRepository.deleteWorkType(workType)
        }
    }

    fun loadProjectsByMonth(date: String) {
        viewModelScope.launch {
            try {
                val parsedDate = LocalDate.parse(date)
                val endOfMonth = parsedDate
                    .withDayOfMonth(parsedDate.month.length(parsedDate.isLeapYear))
                    .toString()
                val projects = getWorkdayByMonthUseCase(date)
                val currentState = _uiState.value
                if (currentState is SettingsUiState.Success) {
                    _uiState.value = currentState.copy(
                        data = currentState.data.copy(
                            endMonthDate = endOfMonth,
                            projectsByMonth = projects
                        )
                    )
                }
            } catch (e: IllegalArgumentException) {
                handleException(e, "Failed to load projects")
            } catch (e: IllegalStateException) {
                handleException(e, "Failed to load projects")
            }
        }
    }

    fun loadSettings() {
        viewModelScope.launch {
            _uiState.value = SettingsUiState.Loading
            try {
                val loadedData = getSettingsUseCase()
                val currentDate = dateRepository.selectedDate.value
                val workStats = projectDetailsRepository.getWorkStatsByDate(currentDate)
                val parsedDate = LocalDate.parse(currentDate)
                val endOfMonth = parsedDate
                    .withDayOfMonth(parsedDate.month.length(parsedDate.isLeapYear))
                    .toString()
                val projects = getWorkdayByMonthUseCase(currentDate)

                _uiState.value = SettingsUiState.Success(
                    data = SettingsState(
                        name = loadedData.name,
                        employer = loadedData.employer,
                        dailyWorkTimeEstimate = workStats?.dailyWorkTimeEstimate ?: "",
                        lunchTimeEstimate = workStats?.dailyLunchTimeEstimate ?: ZERO_TIME,
                        selectedDate = currentDate,
                        endMonthDate = endOfMonth,
                        workTypes = loadedData.workTypes,
                        projectsByMonth = projects
                    )
                )
            } catch (e: IllegalArgumentException) {
                handleException(e, "Failed to load settings")
            } catch (e: IllegalStateException) {
                handleException(e, "Failed to load settings")
            }
        }
    }

    fun saveSettings() {
        viewModelScope.launch {
            try {
                val currentState = _uiState.value
                if (currentState is SettingsUiState.Success) {
                    saveSettingsUseCase(
                        name = currentState.data.name,
                        employer = currentState.data.employer,
                        workTypes = currentState.data.workTypes,
                        dailyWorkTimeEstimate = currentState.data.dailyWorkTimeEstimate,
                        lunchTimeEstimate = currentState.data.lunchTimeEstimate
                    )
                }
            } catch (e: IllegalArgumentException) {
                handleException(e, "Failed to save settings")
            } catch (e: IllegalStateException) {
                handleException(e, "Failed to save settings")
            }
        }
    }

    private fun handleException(exception: Exception, message: String) {
        _uiState.value = SettingsUiState.Error("$message: ${exception.message}")
    }
}

package com.akiwiksten.worktime30.feature.workday

import android.util.Log
import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import com.akiwiksten.worktime30.core.ZERO_TIME
import com.akiwiksten.worktime30.core.calculator.WorkTimeCalculator
import com.akiwiksten.worktime30.data.repository.DateRepository
import com.akiwiksten.worktime30.data.repository.ProjectDetailsRepository
import com.akiwiksten.worktime30.domain.DeleteWorkdayUseCase
import com.akiwiksten.worktime30.domain.GetWorkdayScreenDataUseCase
import com.akiwiksten.worktime30.domain.SaveWorkdayUseCase
import com.akiwiksten.worktime30.feature.projects.details.ProjectDetailsState
import com.akiwiksten.worktime30.feature.projects.details.WorkStatsState
import dagger.hilt.android.lifecycle.HiltViewModel
import kotlinx.coroutines.ExperimentalCoroutinesApi
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.SharingStarted
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.flatMapLatest
import kotlinx.coroutines.flow.map
import kotlinx.coroutines.flow.onStart
import kotlinx.coroutines.flow.stateIn
import kotlinx.coroutines.launch
import java.time.LocalDate
import javax.inject.Inject

data class SingleProjectState(
    val index: Int = -1,
    val projectName: String = "",
    val projectTime: String = ZERO_TIME,
    val kilometres: String = "0",
    val allowance: String = "",
    val workType: String = "",
    val projectDetails: ProjectDetailsState? = null,
    val workStats: WorkStatsState? = null,
    val date: String = ""
)

sealed class WorkdayUiState {
    object Loading : WorkdayUiState()

    data class Success(
        val date: String = "",
        val workTimeToday: String = ZERO_TIME,
        val workTimeTodayEstimate: String = ZERO_TIME,
        val flexTimeToday: String = ZERO_TIME,
        val initialFlexTimeTotal: String = ZERO_TIME,
        val calculatedFlexTimeTotal: String = ZERO_TIME,
        val projects: List<SingleProjectState> = emptyList(),
        val workTypes: List<String> = emptyList()
    ) : WorkdayUiState()

    data class Error(val message: String) : WorkdayUiState()
}

@OptIn(ExperimentalCoroutinesApi::class)
@HiltViewModel
class WorkdayViewModel @Inject constructor(
    private val getWorkdayScreenDataUseCase: GetWorkdayScreenDataUseCase,
    private val saveWorkdayUseCase: SaveWorkdayUseCase,
    private val deleteWorkdayUseCase: DeleteWorkdayUseCase,
    private val projectDetailsRepository: ProjectDetailsRepository,
    private val dateRepository: DateRepository
) : ViewModel() {

    private val refreshTrigger = MutableStateFlow(value = 0)

    val uiState: StateFlow<WorkdayUiState> = refreshTrigger
        .flatMapLatest { dateRepository.selectedDate }
        .map { date ->
            val data = getWorkdayScreenDataUseCase(date)
            val recordedNames = data.projects.map { it.projectName }.toSet()

            val unrecordedProjects = data.projectNames
                .filter { it !in recordedNames }
                .map { name ->
                    SingleProjectState(projectName = name)
                }

            val allProjects = (data.projects + unrecordedProjects)
                .sortedBy { it.projectName }
                .mapIndexed { index, project -> project.copy(index = index) }

            WorkdayUiState.Success(
                date = date,
                workTimeToday = data.projectTime,
                workTimeTodayEstimate = data.workTimeTodayEstimate,
                flexTimeToday = WorkTimeCalculator.calculateFlexTime(
                    initialTime = data.projectTime,
                    addedTime = "-${data.workTimeTodayEstimate}"
                ),
                initialFlexTimeTotal = data.initialFlexTimeTotal,
                calculatedFlexTimeTotal = data.calculatedFlexTimeTotal,
                projects = allProjects,
                workTypes = data.workTypes
            ) as WorkdayUiState
        }
        .onStart { emit(value = WorkdayUiState.Loading) }
        .stateIn(
            scope = viewModelScope,
            started = SharingStarted.Eagerly,
            initialValue = WorkdayUiState.Loading
        )

    fun retryLoad() {
        requestReload()
    }

    private fun requestReload() {
        refreshTrigger.value += 1
    }

    fun saveProject(state: SingleProjectState) {
        viewModelScope.launch {
            try {
                val currentState = uiState.value
                val date = (currentState as? WorkdayUiState.Success)?.date ?: return@launch

                val projectToSave = state.copy(date = date)

                val projectDetailsToSave = state.projectDetails?.copy(
                    date = date,
                    projectName = state.projectName,
                    projectTime = state.projectTime
                ) ?: ProjectDetailsState(
                    date = date,
                    projectName = state.projectName,
                    projectTime = state.projectTime,
                    flexTimeToday = ZERO_TIME
                )

                saveWorkdayUseCase(
                    projectsToSave = listOf(projectToSave),
                    projectDetailsToSave = projectDetailsToSave
                )

                state.workStats?.let { projectDetailsRepository.insertWorkStats(it) }

                requestReload()
            } catch (e: IllegalArgumentException) {
                Log.e("WorkdayViewModel", "saveProject: ", e)
            } catch (e: IllegalStateException) {
                Log.e("WorkdayViewModel", "saveProject: ", e)
            }
        }
    }

    fun deleteProject(state: SingleProjectState) {
        viewModelScope.launch {
            try {
                val currentState = uiState.value
                val date = (currentState as? WorkdayUiState.Success)?.date ?: return@launch

                deleteWorkdayUseCase(date = date, projectName = state.projectName, projectTime = state.projectTime)
                requestReload()
            } catch (e: IllegalArgumentException) {
                Log.e("WorkdayViewModel", "deleteProject: ", e)
            } catch (e: IllegalStateException) {
                Log.e("WorkdayViewModel", "deleteProject: ", e)
            }
        }
    }

    fun updateWorkStats(workTimeTodayEstimate: String, initialFlexTimeTotal: String) {
        if (
            !isValidWorkTimeTodayEstimateInput(workTimeTodayEstimate) ||
            !isValidInitialFlexTimeTotalInput(initialFlexTimeTotal)
        ) {
            return
        }

        viewModelScope.launch {
            try {
                val currentUiState = uiState.value as? WorkdayUiState.Success ?: return@launch
                val isCurrentDay = currentUiState.date == LocalDate.now().toString()
                val canUpdateWorkTimeTodayEstimate = isCurrentDay && currentUiState.workTimeToday == ZERO_TIME
                val currentWorkStats = projectDetailsRepository.getWorkStatsByDate(currentUiState.date)
                val existingWorkTimeTodayEstimate = currentWorkStats?.dailyWorkTime
                    ?.ifEmpty { currentUiState.workTimeTodayEstimate }
                    ?: currentUiState.workTimeTodayEstimate

                projectDetailsRepository.upsertWorkdayStats(
                    date = currentUiState.date,
                    workTimeToday = currentUiState.workTimeToday,
                    workStats = WorkStatsState(
                        dailyWorkTime = if (canUpdateWorkTimeTodayEstimate) {
                            workTimeTodayEstimate
                        } else {
                            existingWorkTimeTodayEstimate
                        },
                        lunchTime = currentWorkStats?.lunchTime ?: ZERO_TIME,
                        initialFlexTimeTotal = initialFlexTimeTotal
                    )
                )
                requestReload()
            } catch (e: IllegalArgumentException) {
                Log.e("WorkdayViewModel", "updateWorkStats: ", e)
            } catch (e: IllegalStateException) {
                Log.e("WorkdayViewModel", "updateWorkStats: ", e)
            }
        }
    }
}

private fun isValidWorkTimeTodayEstimateInput(value: String): Boolean {
    return value.matches(regex = Regex(pattern = "(?:[1-9][0-9]+|0[0-9]):[0-5][0-9]"))
}

private fun isValidInitialFlexTimeTotalInput(value: String): Boolean {
    return value.matches(regex = Regex(pattern = "[+-]?(?:[1-9][0-9]+|0[0-9]):[0-5][0-9]"))
}

